INSERT INTO tp_scenic_spots (Title, Classification, FameLevel, ScenicGrade, Summary, Content, GeoId, Author, IsSticky, IsHome, IsHidden, ShowWatermark, Views, SortOrder, CreatedAt, UpdatedAt) VALUES
('蓬莱阁',         '名胜古迹', '知名景区',   'AAAAA级', '中国四大名楼之一，八仙过海传说发源地，登阁可俯瞰渤海，云雾缭绕时宛如仙境。',         '<p>蓬莱阁始建于北宋嘉祐六年...</p>', 101, '旅游局', 1,1,0,0, 5600,100, NOW(), NOW()),
('烟台山公园',     '网红打卡', '热门景点',   'AAA级',   '近代史上的领事馆聚集地，欧式建筑与海景交融，是烟台最具异域风情的打卡地。',         '<p>烟台山公园坐落于芝罘区...</p>', 100, '旅游局', 0,1,0,0, 3200,100, DATE_SUB(NOW(),INTERVAL 1 DAY), NOW()),
('崂山风景区',     '自然风光', '知名景区',   'AAAAA级', '海上第一名山，道教圣地，奇峰怪石与碧海蓝天相映成趣，是青岛的精神地标。',           '<p>崂山是中国海岸线上最高的山峰...</p>', 12, '旅游局', 0,1,0,0, 4800,100, DATE_SUB(NOW(),INTERVAL 2 DAY), NOW()),
('泰山',           '名胜古迹', '知名景区',   'AAAAA级', '五岳之首，中华民族的精神象征，登顶观日出是每个中国人的心愿。',                     '<p>泰山是中国最著名的山岳之一...</p>', 11, '旅游局', 1,1,0,0, 9800,100, DATE_SUB(NOW(),INTERVAL 3 DAY), NOW()),
('大明湖',         '自然风光', '热门景点',   'AAAA级',  '济南三大名胜之一，夏日荷花盛开，湖光山色，是感受泉城文化的绝佳去处。',             '<p>大明湖位于济南市历下区...</p>', 11, '旅游局', 0,0,0,0, 2100,100, DATE_SUB(NOW(),INTERVAL 4 DAY), NOW()),
('西湖',           '自然风光', '知名景区',   'AAAAA级', '欲把西湖比西子，淡妆浓抹总相宜。断桥残雪、平湖秋月，每一处都是诗。',               '<p>西湖是杭州的标志...</p>', 30, '旅游局', 0,1,0,0, 8800,100, DATE_SUB(NOW(),INTERVAL 5 DAY), NOW()),
('故宫博物院',     '博物馆',   '知名景区',   'AAAAA级', '世界上现存规模最大、保存最完整的木质结构古建筑群，收藏文物逾180万件。',             '<p>故宫，又称紫禁城...</p>', 60, '旅游局', 1,1,0,0,12000,100, DATE_SUB(NOW(),INTERVAL 6 DAY), NOW()),
('宽窄巷子',       '网红打卡', '城市地标',   'AAAA级',  '成都最具代表性的历史文化街区，老成都的生活缩影，茶馆、小吃、民俗一应俱全。',         '<p>宽窄巷子由宽巷子、窄巷子、井巷子组成...</p>', 40, '旅游局', 0,1,0,0, 6500,100, DATE_SUB(NOW(),INTERVAL 7 DAY), NOW()),
('长岛国家公园',   '自然风光', '小众秘境',   'AAAA级',  '黄渤海交汇处的海上仙山，球石滩、九丈崖、月牙湾，每一处都令人叹为观止。',           '<p>长岛由32个岛屿组成...</p>', 104, '旅游局', 0,0,0,0, 1800,100, DATE_SUB(NOW(),INTERVAL 8 DAY), NOW()),
('淄博烧烤街',     '网红打卡', '网红打卡地', 0,      '一炉一卷一碟小葱，灵魂三件套让淄博烧烤火遍全国，成为现象级的城市旅游名片。',         '<p>淄博烧烤以其独特的吃法...</p>', 14, '旅游局', 0,1,0,0, 7200,100, DATE_SUB(NOW(),INTERVAL 9 DAY), NOW()),
('趵突泉',         '名胜古迹', '知名景区',   'AAAA级',  '天下第一泉，泉水昼夜喷涌，水温常年18度，是济南泉城文化的核心象征。',               '<p>趵突泉位于济南市历下区...</p>', 11, '旅游局', 0,1,0,0, 5100,100, DATE_SUB(NOW(),INTERVAL 10 DAY), NOW()),
('青岛栈桥',       '网红打卡', '城市地标',   'AAA级',   '青岛的城市名片，百年历史的海上长廊，回澜阁倒映在碧波之中，是青岛最经典的打卡地。', '<p>青岛栈桥始建于1891年...</p>', 12, '旅游局', 0,1,0,0, 6800,100, DATE_SUB(NOW(),INTERVAL 11 DAY), NOW()),
('威海刘公岛',     '名胜古迹', '知名景区',   'AAAA级',  '甲午战争遗址，中国近代史的见证地，岛上保存着大量珍贵的历史遗迹和文物。',           '<p>刘公岛位于威海湾口...</p>', 13, '旅游局', 0,0,0,0, 2900,100, DATE_SUB(NOW(),INTERVAL 12 DAY), NOW()),
('苏州拙政园',     '名胜古迹', '知名景区',   'AAAAA级', '中国四大名园之首，江南园林的典范，亭台楼阁、假山水池，步步皆景，处处入画。',         '<p>拙政园始建于明代正德年间...</p>', 50, '旅游局', 0,1,0,0, 7600,100, DATE_SUB(NOW(),INTERVAL 13 DAY), NOW()),
('南京中山陵',     '名胜古迹', '知名景区',   'AAAAA级', '中国近代伟大的民主革命先行者孙中山先生的陵寝，依山而建，气势恢宏。',               '<p>中山陵位于南京市玄武区紫金山南麓...</p>', 51, '旅游局', 0,0,0,0, 4300,100, DATE_SUB(NOW(),INTERVAL 14 DAY), NOW()),
('广州陈家祠',     '博物馆',   '热门景点',   'AAAA级',  '岭南建筑艺术的集大成者，精美的砖雕、木雕、石雕令人叹为观止，是广州必游之地。',     '<p>陈家祠建于清光绪年间...</p>', 20, '旅游局', 0,0,0,0, 3400,100, DATE_SUB(NOW(),INTERVAL 15 DAY), NOW()),
('深圳世界之窗',   '游乐园',   '热门景点',   'AAAA级',  '汇聚全球130多处著名景观的主题公园，不出国门即可游览世界，是深圳最受欢迎的景区之一。','<p>世界之窗占地48万平方米...</p>', 21, '旅游局', 0,1,0,0, 5500,100, DATE_SUB(NOW(),INTERVAL 16 DAY), NOW()),
('杭州灵隐寺',     '名胜古迹', '知名景区',   'AAAA级',  '江南禅宗五山之首，千年古刹，飞来峰石刻造像精美绝伦，香火鼎盛，是杭州最重要的寺庙。','<p>灵隐寺始建于东晋咸和元年...</p>', 30, '旅游局', 0,0,0,0, 4700,100, DATE_SUB(NOW(),INTERVAL 17 DAY), NOW()),
('成都大熊猫基地', '自然风光', '知名景区',   'AAAA级',  '全球最大的大熊猫人工繁育研究基地，近距离观赏国宝大熊猫，是成都最受欢迎的景区。',   '<p>成都大熊猫繁育研究基地建于1987年...</p>', 40, '旅游局', 1,1,0,0, 9200,100, DATE_SUB(NOW(),INTERVAL 18 DAY), NOW()),
('烟台养马岛',     '自然风光', '小众秘境',   'AAA级',   '号称东方的小马尔代夫，岛上海水清澈，沙滩洁白，骑马观海是最独特的体验。',           '<p>养马岛位于烟台市牟平区...</p>', 10, '旅游局', 0,0,0,0, 2200,100, DATE_SUB(NOW(),INTERVAL 19 DAY), NOW());


