INSERT INTO tp_travelogues (Title, Classification, MainImage, Summary, Content, GeoId, Author, Source, CopyrightType, IsSticky, IsHome, IsHidden, ShowWatermark, Views, SortOrder, CreatedAt, UpdatedAt) VALUES
('烟台长岛三日游，遇见最美海岸线',       'travelogue', 'https://images.unsplash.com/photo-1540660290370-8af90a454417?w=800', '走进烟台长岛，感受仙山海岛的魅力，球石滩、九丈崖、月牙湾，每一处都令人流连忘返。', '<p>第一天：从烟台港乘船前往长岛...</p>', 104, '徐霞客',  '原创', '原创版权', 1,1,0,0, 5600,100, NOW(), NOW()),
('蓬莱阁攻略：寻访八仙过海的传说',       'guide',      'https://images.unsplash.com/photo-1527685238219-c81b3dd33021?w=800', '蓬莱阁作为中国四大名楼之一，历史悠久，门票信息、游玩路线、周边交通一网打尽。', '<p>蓬莱阁景区包含蓬莱阁主楼、天后宫...</p>', 101, '旅游达人','原创', '原创版权', 0,1,0,0,  890,100, DATE_SUB(NOW(),INTERVAL 1 DAY), NOW()),
('威海环海路自驾记，随手一拍都是大片',   'travelogue', 'https://images.unsplash.com/photo-1508804185872-d7badad00f7d?w=800', '威海的环海路是自驾者的天堂，这条路串联起了威海最美的风景线，全程约200公里。', '<p>从威海市区出发，沿着S301省道一路向东...</p>', 13, '老司机',  '原创', '原创版权', 1,0,0,0, 2300,100, DATE_SUB(NOW(),INTERVAL 2 DAY), NOW()),
('青岛八大关秋色，感受欧式风情的浪漫',   'travelogue', 'https://images.unsplash.com/photo-1444723121867-7a241cacace9?w=800', '八大关的秋天是青岛最有味道的时候，满地的落叶，古老的洋房，在这里迷路也是一种享受。', '<p>八大关因八条以关隘命名的道路而得名...</p>', 12, '摄影师',  '原创', '原创版权', 0,1,0,0, 1560,100, DATE_SUB(NOW(),INTERVAL 3 DAY), NOW()),
('泰山日出观赏指南：不看日出枉上泰山',   'guide',      NULL, '泰山日出是壮丽的自然景观，什么时候爬、穿什么衣服、在哪里看最好，本文一一解答。', '<p>观看泰山日出有两种方式...</p>', 11, '爬山王',  '原创', '原创版权', 1,1,0,0, 3400,100, DATE_SUB(NOW(),INTERVAL 4 DAY), NOW()),
('济南大明湖夏日赏荷，寻找雨荷的足迹',   'travelogue', NULL, '夏日的大明湖，荷花盛开，清香四溢，漫步湖边，感受济南泉城的独特魅力。', '<p>大明湖的荷花一般在6月下旬开始盛开...</p>', 11, '文艺青年','原创', '原创版权', 0,0,0,0, 1100,100, DATE_SUB(NOW(),INTERVAL 5 DAY), NOW()),
('淄博烧烤全攻略：进淄赶烤，不虚此行',   'guide',      NULL, '淄博烧烤火遍全国，灵魂三件套缺一不可，哪家店最好吃、排队技巧、吃法演示全在这里。', '<p>淄博烧烤的精髓在于"小饼卷肉蘸小葱"...</p>', 14, '美食家',  '原创', '原创版权', 1,1,0,0, 5600,100, DATE_SUB(NOW(),INTERVAL 6 DAY), NOW()),
('西湖边的一天：最省钱的杭州游玩方式',   'guide',      NULL, '西湖免费开放，但周边消费不低，本文教你如何花最少的钱，玩最美的西湖。', '<p>西湖景区本身免费，但停车费、游船费是主要花销...</p>', 30, '省钱达人','原创', '原创版权', 0,1,0,0, 2800,100, DATE_SUB(NOW(),INTERVAL 7 DAY), NOW()),
('成都宽窄巷子深度游：不只是打卡',       'travelogue', NULL, '宽窄巷子不只是拍照打卡的地方，这里藏着老成都最真实的生活气息和文化底蕴。', '<p>建议避开周末高峰，工作日上午10点前到达...</p>', 40, '成都通',  '原创', '原创版权', 0,0,0,0, 1900,100, DATE_SUB(NOW(),INTERVAL 8 DAY), NOW()),
('故宫一日游完全攻略：如何不走冤枉路',   'guide',      NULL, '故宫面积72万平方米，一天根本逛不完，本文帮你规划最高效的参观路线。', '<p>建议提前在官网预约门票，旺季需提前7天...</p>', 60, '北京通',  '原创', '原创版权', 0,1,0,0, 4200,100, DATE_SUB(NOW(),INTERVAL 9 DAY), NOW()),
('苏州园林半日游：拙政园的诗意时光',     'travelogue', NULL, '拙政园是中国四大名园之首，亭台楼阁、假山水池，每一处转角都是一幅画。', '<p>建议早上8点开园时进入，避开人流高峰...</p>', 50, '园林迷',  '原创', '原创版权', 0,1,0,0, 2600,100, DATE_SUB(NOW(),INTERVAL 10 DAY), NOW()),
('南京一日游：从中山陵到夫子庙',         'travelogue', NULL, '南京是六朝古都，历史底蕴深厚，中山陵、夫子庙、秦淮河，一天走遍金陵精华。', '<p>建议上午游中山陵，下午逛夫子庙...</p>', 51, '历史迷',  '原创', '原创版权', 0,0,0,0, 1700,100, DATE_SUB(NOW(),INTERVAL 11 DAY), NOW()),
('广州美食地图：老广带你吃遍西关',       'guide',      NULL, '广州是美食之都，早茶、肠粉、云吞面、烧鹅，每一样都是人间美味，本文带你找到最正宗的。', '<p>西关是广州最传统的美食聚集地...</p>', 20, '老广州',  '原创', '原创版权', 0,1,0,0, 3800,100, DATE_SUB(NOW(),INTERVAL 12 DAY), NOW()),
('深圳一日游：从城市到自然的完美切换',   'travelogue', NULL, '深圳不只有高楼大厦，梧桐山、大鹏古城、东西涌，自然与历史在这里完美融合。', '<p>建议早上去梧桐山看日出，下午去大鹏古城...</p>', 21, '深漂族',  '原创', '原创版权', 0,0,0,0, 2100,100, DATE_SUB(NOW(),INTERVAL 13 DAY), NOW()),
('烟台趵突泉公园：泉城文化的精髓',       'travelogue', NULL, '趵突泉是天下第一泉，泉水昼夜喷涌，水温常年18度，是济南最值得打卡的地方之一。', '<p>趵突泉公园内有七十二名泉...</p>', 11, '泉城人',  '原创', '原创版权', 0,0,0,0, 1400,100, DATE_SUB(NOW(),INTERVAL 14 DAY), NOW()),
('杭州灵隐寺祈福攻略：最灵验的许愿地',   'guide',      NULL, '灵隐寺是江南禅宗五山之首，千年古刹，飞来峰石刻精美，是杭州最重要的宗教圣地。', '<p>建议早上7点前到达，避开人流高峰...</p>', 30, '佛系青年','原创', '原创版权', 0,1,0,0, 3100,100, DATE_SUB(NOW(),INTERVAL 15 DAY), NOW()),
('成都大熊猫基地：与国宝的亲密接触',     'travelogue', NULL, '全球最大的大熊猫人工繁育研究基地，近距离观赏国宝大熊猫，是成都最受欢迎的景区。', '<p>建议早上8点开园时进入，此时熊猫最活跃...</p>', 40, '熊猫迷',  '原创', '原创版权', 1,1,0,0, 6800,100, DATE_SUB(NOW(),INTERVAL 16 DAY), NOW()),
('威海刘公岛：铭记历史，勿忘国耻',       'travelogue', NULL, '甲午战争遗址，中国近代史的见证地，岛上保存着大量珍贵的历史遗迹和文物。', '<p>刘公岛是甲午战争的主战场之一...</p>', 13, '历史控',  '原创', '原创版权', 0,0,0,0, 1600,100, DATE_SUB(NOW(),INTERVAL 17 DAY), NOW()),
('宁波天一阁：中国现存最古老的私家藏书楼','travelogue', NULL, '天一阁建于明代，是中国现存最古老的私家藏书楼，藏书丰富，建筑精美，是宁波的文化地标。', '<p>天一阁建于明嘉靖年间，距今已有400多年历史...</p>', 31, '书虫',    '原创', '原创版权', 0,0,0,0, 1200,100, DATE_SUB(NOW(),INTERVAL 18 DAY), NOW()),
('烟台养马岛：骑马看海的浪漫体验',       'travelogue', NULL, '号称东方的小马尔代夫，岛上海水清澈，沙滩洁白，骑马观海是最独特的体验。', '<p>养马岛位于烟台市牟平区，乘船约20分钟可达...</p>', 10, '度假党',  '原创', '原创版权', 0,0,0,0, 1900,100, DATE_SUB(NOW(),INTERVAL 19 DAY), NOW());


