INSERT INTO tp_foods (Title, ProductType, Classification, SpecialtyLevel, NonLegacyLevel, Summary, Content, GeoId, Author, IsSticky, IsHome, IsHidden, ShowWatermark, Views, SortOrder, CreatedAt, UpdatedAt) VALUES
('烟台鲅鱼饺子',   '美食', '鲁菜',     NULL,           '省级非遗', '个大肉厚，鲜嫩多汁，咬一口满嘴生鲜，是烟台开海季的必吃美味。', '<p>鲅鱼饺子以鲜鲅鱼为馅...</p>', 10, '美食家', 1,1,0,0, 3500,100, NOW(), NOW()),
('龙口粉丝',       '特产', '海鲜干货', '地理标志产品', '国家级非遗', '色泽洁白，质地柔韧，久煮不碎，素有"粉丝之王"的美誉。', '<p>龙口粉丝有着悠久的历史...</p>', 10, '特产达人', 1,1,0,0, 2800,100, DATE_SUB(NOW(),INTERVAL 1 DAY), NOW()),
('蓬莱小面',       '美食', '鲁菜',     NULL,           '市级非遗', '面条纤细，卤汁鲜美，带有浓郁的海鲜风味，早起一碗热气腾腾。', '<p>蓬莱小面是胶东地区的传统名吃...</p>', 101, '本地人', 0,0,0,0, 1500,100, DATE_SUB(NOW(),INTERVAL 2 DAY), NOW()),
('莱阳梨',         '特产', '时令水果', '地理标志产品', '省级非遗', '皮薄肉细，汁多清甜，入口即化，是著名的滋补佳果。', '<p>莱阳梨主产于五龙河流域...</p>', 10, '果农', 0,0,0,0, 4200,100, DATE_SUB(NOW(),INTERVAL 3 DAY), NOW()),
('麻婆豆腐',       '美食', '川菜',     NULL,           NULL,       '麻、辣、烫、香、酥、嫩、鲜、活，色泽红亮，极具川菜灵魂。', '<p>陈麻婆豆腐始创于清代...</p>', 40, '川厨', 0,1,0,0, 5600,100, DATE_SUB(NOW(),INTERVAL 4 DAY), NOW()),
('广式早茶点心',   '美食', '粤菜',     NULL,           '省级非遗', '品种繁多，精致玲珑，咸甜适口，体现了老广州深厚的茶楼文化。', '<p>"一盅两件"是老广生活的缩照...</p>', 20, '茶楼', 0,1,0,0, 2100,100, DATE_SUB(NOW(),INTERVAL 5 DAY), NOW()),
('大佛龙井',       '特产', '名优茶茗', '地理标志产品', '国家级非遗', '色绿、香郁、味甘、形美，冲泡后茶香四溢，回甘隽永。', '<p>产于新昌，依托大佛寺深厚的文化底蕴...</p>', 31, '茶农', 0,0,0,0, 3200,100, DATE_SUB(NOW(),INTERVAL 6 DAY), NOW()),
('扬州炒饭',       '美食', '苏菜',     NULL,           '市级非遗', '颗粒分明，配料丰富，色泽鲜亮，每一粒米都包裹着蛋香。', '<p>扬州炒饭历史悠久...</p>', 51, '厨师', 0,0,0,0, 1200,100, DATE_SUB(NOW(),INTERVAL 7 DAY), NOW()),
('长岛海参',       '特产', '海鲜干货', '地理标志产品', 0,       '肉质厚实，刺尖挺拔，口感Q弹，是名贵的海味补品。', '<p>长岛位于黄渤海交汇处...</p>', 104, '渔民', 0,0,0,0,  550,100, DATE_SUB(NOW(),INTERVAL 8 DAY), NOW()),
('栖霞苹果',       '特产', '时令水果', '地理标志产品', 0,       '果形端正，色泽红润，脆多汁，酸甜适中，栖霞被誉为"中国苹果之都"。', '<p>栖霞被誉为"中国苹果之都"...</p>', 10, '果农', 0,0,0,0, 1100,100, DATE_SUB(NOW(),INTERVAL 9 DAY), NOW()),
('松鼠桂鱼',       '美食', '苏菜',     NULL,           '市级非遗', '形如松鼠，外脆里嫩，酸甜适口，是苏帮菜中的看家名作。', '<p>选用鲜活桂鱼，改刀精细，下油锅炸至金黄...</p>', 50, '苏厨', 0,0,0,0, 1800,100, DATE_SUB(NOW(),INTERVAL 10 DAY), NOW()),
('顺德鱼生',       '美食', '粤菜',     NULL,           '国家级非遗', '晶莹剔透，口感爽滑，配以各种辅料，极度考验厨师刀工。', '<p>顺德被称为"世界美食之都"...</p>', 20, '粤厨', 0,0,0,0, 2500,100, DATE_SUB(NOW(),INTERVAL 11 DAY), NOW()),
('自贡灯影牛肉',   '美食', '川菜',     NULL,           '国家级非遗', '薄如蝉翼，透影可见，红亮香脆，是极佳的下酒小食。', '<p>灯影牛肉历史源远流长...</p>', 40, '川厨', 0,0,0,0,  480,100, DATE_SUB(NOW(),INTERVAL 12 DAY), NOW()),
('苏州糖果',       '特产', '传统点心', 0,           '省级非遗', '色彩斑斓，甜而不腻，花样繁多，深受小朋友和游客喜爱。', '<p>苏州糖果有着"苏式生活"的缩影...</p>', 50, '糖果匠', 0,0,0,0,  670,100, DATE_SUB(NOW(),INTERVAL 13 DAY), NOW()),
('广式月饼',       '特产', '传统点心', 0,           '省级非遗', '皮薄馅丰，口感细腻，图案精美，是中秋团圆的首选。', '<p>广式月饼以莲蓉蛋黄最为出名...</p>', 20, '饼师', 0,0,0,0, 2600,100, DATE_SUB(NOW(),INTERVAL 14 DAY), NOW()),
('蓬莱八仙宴',     '美食', '鲁菜',     NULL,           '市级非遗', '以海鲜为主，融入八仙过海传说，既是美食盛宴，也是文化大餐。', '<p>蓬莱作为人间仙境，八仙宴是其最顶级的国宴级料理...</p>', 101, '御厨', 0,0,0,0, 1350,100, DATE_SUB(NOW(),INTERVAL 15 DAY), NOW()),
('西湖醋鱼',       '美食', '苏菜',     NULL,           NULL,       '鱼肉嫩美，带有螃蟹味，酸甜适口，是西湖边的一道雅菜。', '<p>选用西湖鲲鱼，烹制前先在笼中饿养两天...</p>', 30, '杭厨', 0,0,0,0,  890,100, DATE_SUB(NOW(),INTERVAL 16 DAY), NOW()),
('东北酸菜白肉',   '美食', '东北菜',   NULL,           NULL,       '酸菜爽脆，白肉肥而不腻，汤汁鲜美，是东北冬天最暖心的家常菜。', '<p>东北酸菜白肉是东北人冬天的标配...</p>', 11, '东北厨', 0,0,0,0,  760,100, DATE_SUB(NOW(),INTERVAL 17 DAY), NOW()),
('烟台大樱桃',     '特产', '时令水果', '地理标志产品', 0,       '个大色艳，甜脆多汁，是烟台最具代表性的水果特产，每年五月是最佳采摘季。', '<p>烟台大樱桃因其独特的地理气候条件...</p>', 10, '果农', 0,1,0,0, 3800,100, DATE_SUB(NOW(),INTERVAL 18 DAY), NOW()),
('成都担担面',     '美食', '川菜',     NULL,           '市级非遗', '面条细滑，麻辣鲜香，芽菜碎肉，一碗下肚浑身舒畅，是成都街头最经典的小吃。', '<p>担担面因旧时小贩挑担沿街叫卖而得名...</p>', 40, '面馆', 0,0,0,0, 2200,100, DATE_SUB(NOW(),INTERVAL 19 DAY), NOW());


