INSERT INTO tp_creative_products (Title, Classification, NonLegacyLevel, Summary, Content, GeoId, Author, Source, IsSticky, IsHome, IsHidden, ShowWatermark, Views, SortOrder, CreatedAt, UpdatedAt) VALUES
('手工苏绣·锦绣山河屏风',     '非遗传承', '国家级', '采用传统平针绣工艺，历时八个月手工打造，展现江南山水的灵动与壮美。', '<p>苏绣作为中国四大名绣之一...</p>', 50, '陆绣娘', '苏绣工坊',     1,1,0,0, 2500,100, NOW(), NOW()),
('故宫联名·瑞兽镇纸',         '工艺礼品', '省级',   '灵感取自故宫屋脊兽，精选黄铜精铸，寓意祥瑞平安，办公书房佳品。', '<p>此款镇纸选取了故宫最受欢迎的狮子与天马造型...</p>', 60, '文创部', '故宫文创',     1,1,0,0, 3200,100, DATE_SUB(NOW(),INTERVAL 1 DAY), NOW()),
('秦始皇兵马俑·盲盒手办',     '时尚潮玩', '市级',   '将威严的兵马俑转化为呆萌可爱的Q版形象，共6款常规项+1款隐藏项。', '<p>"秦俑有礼"系列盲盒...</p>', 40, '设计组', '秦陵文创',     0,1,0,0, 5600,100, DATE_SUB(NOW(),INTERVAL 2 DAY), NOW()),
('非遗油纸伞·繁花似锦',       '非遗传承', '国家级', '天然楠竹骨架，手工皮纸伞面，反复刷纯熟桐油，晴雨两用，古色古香。', '<p>泸州油纸伞是中国油纸伞的"活化石"...</p>', 40, '毕老师', '泸州伞厂',     0,0,0,0, 1200,100, DATE_SUB(NOW(),INTERVAL 3 DAY), NOW()),
('景德镇·手绘玲珑釉里红瓶',   '工艺礼品', '国家级', '玲珑工艺结合釉里红装饰，晶莹剔透中透出那一抹动人的中国红。', '<p>景德镇陶瓷历经千年窑火...</p>', 51, '胡画师', '景德镇陶瓷厂', 0,0,0,0, 2100,100, DATE_SUB(NOW(),INTERVAL 4 DAY), NOW()),
('北京景泰蓝·锦绣花卉首饰盒', '工艺礼品', '国家级', '掐丝流畅，填釉饱满，经过六次烧制磨光，色彩鲜艳且永不褪色。', '<p>景泰蓝，学名掐丝珐琅，曾是皇家御用珍玩...</p>', 60, '张匠人', '北京珐琅厂',   0,0,0,0, 1500,100, DATE_SUB(NOW(),INTERVAL 5 DAY), NOW()),
('蜀锦·熊猫戏竹团扇',         '非遗传承', '国家级', '以蜀锦织就憨态可掬的熊猫形象，真丝包边，紫檀木柄，尽显高雅。', '<p>蜀锦与苏绣结合，这款团扇不仅是纳凉工具...</p>', 40, '陈绣娘', '成都蜀锦织绣博物馆', 0,1,0,0, 2800,100, DATE_SUB(NOW(),INTERVAL 6 DAY), NOW()),
('潍坊·杨家埠木版年画',       '非遗传承', '国家级', '传统梨木版雕刻，人工拓印，色彩艳丽，寓意生活富足、年年顺心。', '<p>杨家埠年画历史悠久...</p>', 14, '杨传人', '年画博物馆',   0,0,0,0,  320,100, DATE_SUB(NOW(),INTERVAL 7 DAY), NOW()),
('宜兴紫砂·石瓢壶',           '工艺礼品', '省级',   '选用原矿黄龙山底槽清泥料，经典石瓢造型，出水有力，握感舒适。', '<p>紫砂壶不仅是茶具，更是文人雅士的收藏品...</p>', 50, '周艺师', '宜兴紫砂厂',   0,0,0,0, 2600,100, DATE_SUB(NOW(),INTERVAL 8 DAY), NOW()),
('苗族·手工蜡染桌旗',         '非遗传承', '国家级', '纯天然植物靛蓝染色，图案多为蝴蝶、鱼纹，充满古朴的民族风情。', '<p>蜡染被称为"画在布上的历史"...</p>', 40, '杨阿妈', '丹寨蜡染工坊', 0,0,0,0,  670,100, DATE_SUB(NOW(),INTERVAL 9 DAY), NOW()),
('敦煌飞天·丝绸书签套装',     '办公文具', '省级',   '以敦煌飞天壁画为设计灵感，采用高清织锦工艺，手感细腻，极具艺术收藏价值。', '<p>书签图案选取了莫高窟第285窟的经典飞天形象...</p>', 40, '艺术部', '敦煌研究院',   0,0,0,0,  900,100, DATE_SUB(NOW(),INTERVAL 10 DAY), NOW()),
('皮影戏·Q版书灯',             '时尚潮玩', '省级',   '利用透光原理将皮影艺术与现代灯具结合，折叠式设计，不仅是灯更是摆件。', '<p>陕西皮影历史悠久...</p>', 40, '创意组', '陕西皮影协会', 0,0,0,0,  450,100, DATE_SUB(NOW(),INTERVAL 11 DAY), NOW()),
('藏银·手工嘎乌盒吊坠',       '工艺礼品', '国家级', '纯手工掐丝，镶嵌绿松石与珊瑚，内可藏经文，寄托虔诚的祝福。', '<p>嘎乌盒在藏语中意为"随身的佛龛"...</p>', 40, '桑布大师','拉萨手工社',  0,1,0,0, 1100,100, DATE_SUB(NOW(),INTERVAL 12 DAY), NOW()),
('徽州·龙尾砚',               '办公文具', '国家级', '质地坚润，发墨如油，砚面浮雕黄山美景，文房四宝之首选。', '<p>歙砚产于安徽歙县，以龙尾山石为贵...</p>', 51, '汪大师', '歙砚协会',     0,0,0,0, 1350,100, DATE_SUB(NOW(),INTERVAL 13 DAY), NOW()),
('内画·京味烟壶摆件',         '工艺礼品', '国家级', '方寸之间见乾坤，细笔在瓶内壁反向作画，绘制老北京街头风情。', '<p>内画是中国传统艺术的一绝...</p>', 60, '刘画师', '内画艺术馆',   0,0,0,0,  720,100, DATE_SUB(NOW(),INTERVAL 14 DAY), NOW()),
('自贡·锦鲤花灯DIY材料包',   '时尚潮玩', '省级',   '配套完整骨架、绸缎及LED灯串，扫码看视频，在家也能做非遗花灯。', '<p>让自贡彩灯从景区走进家庭...</p>', 40, '自贡灯彩组','自贡彩灯厂', 0,0,0,0,  480,100, DATE_SUB(NOW(),INTERVAL 15 DAY), NOW()),
('广州木雕·红木镂空笔筒',     '办公文具', '省级',   '采用优质大红酸枝，多层立体雕刻，通透玲珑，展现广式木雕的高超技艺。', '<p>广作木雕以精巧华丽著称...</p>', 20, '陈木匠', '广州木雕厂',   0,0,0,0,  550,100, DATE_SUB(NOW(),INTERVAL 16 DAY), NOW()),
('东阳木雕·福禄寿禧挂牌',     '工艺礼品', '国家级', '精选花梨木，深度浮雕工艺，福、禄、寿、禧字样圆润饱满，送礼佳品。', '<p>东阳木雕以平面浮雕为主...</p>', 31, '杜师傅', '东阳木雕城',   0,0,0,0,  890,100, DATE_SUB(NOW(),INTERVAL 17 DAY), NOW()),
('云南建水·紫陶汽锅',         '工艺礼品', '国家级', '无釉磨光，质地坚硬如铁，敲击声如磬，蒸出的鸡肉鲜美滑嫩。', '<p>建水紫陶是四大名陶之一...</p>', 40, '李陶艺', '建水紫陶工坊', 0,0,0,0, 1050,100, DATE_SUB(NOW(),INTERVAL 18 DAY), NOW()),
('烟台剪纸·吉祥如意套装',     '非遗传承', '省级',   '胶东剪纸技艺传承百年，图案喜庆吉祥，线条流畅，是烟台最具代表性的民间艺术。', '<p>烟台剪纸以其独特的胶东风格著称...</p>', 10, '剪纸传人','烟台民艺馆',  0,0,0,0,  380,100, DATE_SUB(NOW(),INTERVAL 19 DAY), NOW());

